UPDATE room_join_requests
SET status = 'REJECTED', rejected_at = #{rejectedAt}, version = version + 1
WHERE id = #{joinRequestId} AND status = 'PENDING' AND version = #{version}

UPDATE room_join_requests
SET status = 'PENDING', accepted_by = NULL, accepted_at = NULL, undo_deadline_at = NULL,
    version = version + 1
WHERE id = #{joinRequestId} AND status = 'ACCEPTED' AND version = #{version}
  AND accepted_by = #{acceptedBy}
